export const PALETTE_GOOD: string[] = ['#c8f064','#64f096','#64d4f0','#a0f064','#64f0c8','#f0e464','#96f064','#64f0e4'];
export const PALETTE_BAD: string[] = ['#f06464','#f09664','#f0c864','#e06488','#f06496','#d06450','#f07850','#e85050'];
export const PALETTE_MID: string[] = ['#b464f0','#9064f0','#6480f0','#6496d0','#6478d0','#7864f0','#a064d0'];

export const goodNuevo: string[] = ['202505','202506','202507','202508','202509','202510','202511','202512'];
export const goodRenov: string[] = ['202408','202409','202410','202411','202412','202501','202502','202503','202504'];
export const POOL_AA_THRESHOLD = 25;

export function getColor(v: string, section: string): string {
  const good = section === 'NUEVO' ? goodNuevo : goodRenov;
  const isGood = good.includes(v);
  const yr = parseInt(v.slice(0,4)), mo = parseInt(v.slice(4));
  const idx = (yr-2023)*12 + mo;
  if(isGood) return PALETTE_GOOD[good.indexOf(v) % PALETTE_GOOD.length];
  if(parseInt(v) >= 202307 && parseInt(v) <= 202407) return PALETTE_BAD[(idx) % PALETTE_BAD.length];
  return PALETTE_MID[(idx) % PALETTE_MID.length];
}

export function makeCurveDatasets(section: string, bucket: string, filter: string): { labels: string[]; datasets: any[] } {
  const allV = Object.keys(CURVES[section]);
  const goodList = section === 'NUEVO' ? goodNuevo : goodRenov;
  const filtered = filter === 'good' ? allV.filter(v=>goodList.includes(v))
                 : filter === 'bad'  ? allV.filter(v=>!goodList.includes(v) && parseInt(v)<=202407)
                 : allV;
  
  let maxMob = 0;
  filtered.forEach(v => {
    const d = CURVES[section][v];
    if(d && d[bucket]) maxMob = Math.max(maxMob, ...Object.keys(d[bucket]).map(Number));
  });
  
  const labels = Array.from({length: maxMob+1}, (_,i) => 'MoB '+i);
  const datasets = filtered.map(v => {
    const d = CURVES[section][v];
    if(!d || !d[bucket]) return null;
    const pts = Array.from({length: maxMob+1}, (_,i) => d[bucket][i] !== undefined ? d[bucket][i] : null);
    const good = section === 'NUEVO' ? goodNuevo : goodRenov;
    const isGood = good.includes(v);
    return {
      label: v,
      data: pts,
      borderColor: getColor(v, section),
      backgroundColor: 'transparent',
      borderWidth: isGood ? 2.5 : 1.5,
      pointRadius: isGood ? 2.5 : 1,
      tension: 0.3,
      spanGaps: false,
      borderDash: isGood ? [] : [4,3],
    };
  }).filter(Boolean);
  return {labels, datasets};
}



